import{_ as t,a,b as o,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as n,c as s,a2 as r}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"إضافة قناة Google Drive","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/upload/google-drive.md","filePath":"ar-SA/upload/google-drive.md","lastUpdated":1781962217000}'),d={name:"ar-SA/upload/google-drive.md"};function c(p,e,h,g,u,b){return n(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="إضافة-قناة-google-drive" tabindex="-1">إضافة قناة Google Drive <a class="header-anchor" href="#إضافة-قناة-google-drive" aria-label="Permalink to &quot;إضافة قناة Google Drive&quot;">​</a></h1><h2 id="ما-الذي-تحتاجه-أولًا؟" tabindex="-1">ما الذي تحتاجه أولًا؟ <a class="header-anchor" href="#ما-الذي-تحتاجه-أولًا؟" aria-label="Permalink to &quot;ما الذي تحتاجه أولًا؟&quot;">​</a></h2><p>قبل البدء جهّز هذه العناصر:</p><table tabindex="0"><thead><tr><th>المتطلب</th><th>لماذا تحتاجه</th></tr></thead><tbody><tr><td>حساب Google</td><td>للوصول إلى Google Cloud وتفويض Google Drive</td></tr><tr><td>مشروع Google Cloud</td><td>لتفعيل Drive API وإنشاء OAuth credentials</td></tr><tr><td>OAuth 2.0 client</td><td>يستخدمه ImgBed للحصول على <code>Client ID</code> و <code>Client Secret</code> و <code>Refresh Token</code></td></tr><tr><td>نطاق ImgBed الخاص بك</td><td>لاستخدامه في OAuth redirect URI. يجب أن يطابق النطاق الذي تستخدمه فعليًا.</td></tr></tbody></table><h2 id="خطوات-الإعداد" tabindex="-1">خطوات الإعداد <a class="header-anchor" href="#خطوات-الإعداد" aria-label="Permalink to &quot;خطوات الإعداد&quot;">​</a></h2><h3 id="الخطوة-1-فعّل-google-drive-api" tabindex="-1">الخطوة 1: فعّل Google Drive API <a class="header-anchor" href="#الخطوة-1-فعّل-google-drive-api" aria-label="Permalink to &quot;الخطوة 1: فعّل Google Drive API&quot;">​</a></h3><ol><li>افتح Google Cloud Console.</li><li>أنشئ مشروعًا جديدًا أو اختر مشروعًا موجودًا.</li><li>انتقل إلى <code>APIs &amp; Services</code>.</li><li>اضغط <code>Enable APIs and Services</code>.</li><li>ابحث عن <code>Google Drive API</code>.</li><li>افتحه واضغط enable.</li></ol><h3 id="الخطوة-2-اضبط-oauth-consent-screen" tabindex="-1">الخطوة 2: اضبط OAuth Consent Screen <a class="header-anchor" href="#الخطوة-2-اضبط-oauth-consent-screen" aria-label="Permalink to &quot;الخطوة 2: اضبط OAuth Consent Screen&quot;">​</a></h3><ol><li>في Google Cloud افتح <code>Google Auth Platform</code>.</li><li>أكمل معلومات <code>Branding</code> الأساسية، مثل اسم التطبيق وبريد الدعم وبريد تواصل المطور.</li><li>افتح <code>Audience</code>.</li><li>لمعظم عمليات النشر الشخصية ذاتية الاستضافة اختر <code>External</code>.</li><li>إذا اخترت <code>External</code> فأضف حساب Google الذي تريد تفويضه ضمن <code>Test users</code>.</li><li>افتح <code>Data Access</code>.</li><li>أضف صلاحيات Google Drive المطلوبة.</li></ol><h3 id="الخطوة-3-أنشئ-oauth-2-0-client" tabindex="-1">الخطوة 3: أنشئ OAuth 2.0 Client <a class="header-anchor" href="#الخطوة-3-أنشئ-oauth-2-0-client" aria-label="Permalink to &quot;الخطوة 3: أنشئ OAuth 2.0 Client&quot;">​</a></h3><ol><li>في <code>Google Auth Platform</code> افتح <code>Clients</code>.</li><li>أنشئ client جديدًا.</li><li>اجعل application type هو <code>Web application</code>.</li><li>أعطِ الـ client اسمًا واضحًا.</li><li>في authorized JavaScript origins أدخل رابط ImgBed، مثل:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com</span></span></code></pre></div><ol start="6"><li>في authorized redirect URIs أدخل:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://img.example.com/api/oauth/google/callback</span></span></code></pre></div><p><img src="'+t+'" alt="إنشاء OAuth client" loading="lazy"></p><p><img src="'+a+'" alt="إدخال النطاق و callback URL" loading="lazy"></p><p>بعد إنشاء client انسخ القيم التالية:</p><table tabindex="0"><thead><tr><th>القيمة الناتجة</th><th>حقل ImgBed</th></tr></thead><tbody><tr><td>Client ID</td><td><code>Client ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret</code></td></tr></tbody></table><h2 id="الخطوة-4-املأ-قناة-google-drive" tabindex="-1">الخطوة 4: املأ قناة Google Drive <a class="header-anchor" href="#الخطوة-4-املأ-قناة-google-drive" aria-label="Permalink to &quot;الخطوة 4: املأ قناة Google Drive&quot;">​</a></h2><p>في إعدادات الرفع اختر <code>Google Drive</code> واملأ:</p><table tabindex="0"><thead><tr><th>حقل ImgBed</th><th>ما الذي تدخله</th></tr></thead><tbody><tr><td>Channel name</td><td>اسم واضح، مثل <code>Main Google Drive</code></td></tr><tr><td>Client ID</td><td>Client ID من Google Cloud</td></tr><tr><td>Client Secret</td><td>Client Secret من Google Cloud</td></tr><tr><td>Refresh Token</td><td>اتركه فارغًا الآن. تحصل عليه في الخطوة التالية.</td></tr><tr><td>Root directory</td><td>اختياري. الافتراضي <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="لصق بيانات client في ImgBed" loading="lazy"></p><h2 id="الخطوة-5-احصل-على-refresh-token" tabindex="-1">الخطوة 5: احصل على Refresh Token <a class="header-anchor" href="#الخطوة-5-احصل-على-refresh-token" aria-label="Permalink to &quot;الخطوة 5: احصل على Refresh Token&quot;">​</a></h2><ol><li>اضغط <code>Get Token</code>.</li><li>اختر حساب Google الذي تريد ربطه.</li><li>أكمل رسائل التفويض.</li><li>ستعرض صفحة callback قيمة <code>Refresh Token</code>.</li><li>انسخها.</li><li>ارجع إلى ImgBed والصقها في حقل <code>Refresh Token</code>.</li></ol><p><img src="'+l+`" alt="نسخ Refresh Token بعد التفويض" loading="lazy"></p><p>إذا غيّرت حساب Google لاحقًا، أو بدّلت OAuth client، أو انتهت صلاحية التفويض القديم، فلا تحتاج إلى حذف القناة. افتح صفحة التحرير واضغط <code>Reauthorize</code>.</p><h2 id="الخطوة-6-احفظ-القناة" tabindex="-1">الخطوة 6: احفظ القناة <a class="header-anchor" href="#الخطوة-6-احفظ-القناة" aria-label="Permalink to &quot;الخطوة 6: احفظ القناة&quot;">​</a></h2><p>بعد ملء جميع الحقول احفظ القناة.</p><h2 id="المسار-السريع" tabindex="-1">المسار السريع <a class="header-anchor" href="#المسار-السريع" aria-label="Permalink to &quot;المسار السريع&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>افتح Google Cloud</span></span>
<span class="line"><span>-&gt; أنشئ مشروعًا أو اختر مشروعًا</span></span>
<span class="line"><span>-&gt; فعّل Google Drive API</span></span>
<span class="line"><span>-&gt; اضبط Google Auth Platform</span></span>
<span class="line"><span>-&gt; إذا كان Audience هو External فأضف حساب Google إلى Test users</span></span>
<span class="line"><span>-&gt; أنشئ Web application OAuth client</span></span>
<span class="line"><span>-&gt; استخدم https://your-domain.com/api/oauth/google/callback كـ redirect URI</span></span>
<span class="line"><span>-&gt; أدخل Client ID و Client Secret في ImgBed</span></span>
<span class="line"><span>-&gt; اضغط Get Token</span></span>
<span class="line"><span>-&gt; سجّل الدخول بـ Google وفوّض</span></span>
<span class="line"><span>-&gt; انسخ Refresh Token من صفحة callback</span></span>
<span class="line"><span>-&gt; الصقه في ImgBed واحفظ</span></span>
<span class="line"><span>-&gt; ارفع صورة تجريبية</span></span></code></pre></div><h2 id="مراجع" tabindex="-1">مراجع <a class="header-anchor" href="#مراجع" aria-label="Permalink to &quot;مراجع&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications: <a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration: <a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scopes: <a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const f=i(d,[["render",c]]);export{k as __pageData,f as default};
